mapper.select:
SELECT ca.id, ca.user_id AS userId, u.nick_name AS nickName, u.avatar_url AS avatarUrl, ca.college_id AS collegeId, c.name AS collegeName, ca.student_no AS studentNo, ca.class_name AS className, ca.cert_image AS certImage, ca.status, ca.reject_reason AS rejectReason, ca.review_time AS reviewTime, ca.create_time AS createTime FROM campus_auth ca LEFT JOIN user u ON ca.user_id = u.id LEFT JOIN college c ON ca.college_id = c.id
AND ca.status = #{status}
AND ca.college_id = #{collegeId}
AND ca.id = #{id}
ORDER BY ca.create_time DESC
